import{_ as a,o as r,c as t,S as s}from"./chunks/framework.DZlzLDBr.js";const u=JSON.parse('{"title":"Ordered Questions","description":"","frontmatter":{},"headers":[],"relativePath":"Ordered-Questions.md","filePath":"Ordered-Questions.md","lastUpdated":null}'),i={name:"Ordered-Questions.md"};function o(n,e,d,l,c,p){return r(),t("div",null,[...e[0]||(e[0]=[s(`<h1 id="ordered-questions" tabindex="-1">Ordered Questions <a class="header-anchor" href="#ordered-questions" aria-label="Permalink to &quot;Ordered Questions&quot;">​</a></h1><p>Last modified: 14/02/2026</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Ordered Question cards test whether you can place items in the correct sequence. Sprout stores your list in the right order, then scrambles it during review.</p><p>Use this card type for steps, timelines, rankings, and other ordered lists.</p><h2 id="writing-an-ordered-question-card" tabindex="-1">Writing an ordered question card <a class="header-anchor" href="#writing-an-ordered-question-card" aria-label="Permalink to &quot;Writing an ordered question card&quot;">​</a></h2><p>Use <code>OQ</code> for the prompt and numbered fields (<code>1</code>, <code>2</code>, <code>3</code>, …) for items in the correct order:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>T | Cardiac cycle |</span></span>
<span class="line"><span>OQ | Arrange the phases of the cardiac cycle in order |</span></span>
<span class="line"><span>1 | Atrial systole |</span></span>
<span class="line"><span>2 | Isovolumetric contraction |</span></span>
<span class="line"><span>3 | Ventricular ejection |</span></span>
<span class="line"><span>4 | Isovolumetric relaxation |</span></span>
<span class="line"><span>5 | Ventricular filling |</span></span>
<span class="line"><span>I | The cycle repeats with each heartbeat |</span></span>
<span class="line"><span>G | Cardiology |</span></span></code></pre></div><ul><li><code>OQ</code>: required question prompt.</li><li><code>1</code>, <code>2</code>, <code>3</code>, ...: ordered items. Add at least 2 items.</li></ul><p>If item order is wrong in the note, Sprout will treat that wrong order as the answer key.</p><h2 id="using-the-modal" tabindex="-1">Using the modal <a class="header-anchor" href="#using-the-modal" aria-label="Permalink to &quot;Using the modal&quot;">​</a></h2><ol><li>Right-click in a note → <strong>Add flashcard → Ordered Question Card</strong>.</li><li>Enter the prompt.</li><li>Add items in the correct order.</li><li>Optionally add title, info, and groups.</li><li>Click <strong>Save</strong>.</li></ol><p>You can drag items up or down before saving.</p><h2 id="how-ordered-questions-are-reviewed" tabindex="-1">How ordered questions are reviewed <a class="header-anchor" href="#how-ordered-questions-are-reviewed" aria-label="Permalink to &quot;How ordered questions are reviewed&quot;">​</a></h2><p>During review, items appear in a scrambled order. Arrange them into the correct sequence.</p><p>After you submit:</p><ul><li>If all positions are correct, the card is graded <strong>Good</strong>.</li><li>If any position is wrong, the card is graded <strong>Again</strong> and the correct order is shown.</li></ul><h2 id="grading-behaviour" tabindex="-1">Grading behaviour <a class="header-anchor" href="#grading-behaviour" aria-label="Permalink to &quot;Grading behaviour&quot;">​</a></h2><p>Ordered Questions are auto-graded:</p><table tabindex="0"><thead><tr><th>Your arrangement</th><th>Grade applied</th></tr></thead><tbody><tr><td>Fully correct order</td><td><strong>Good</strong></td></tr><tr><td>Any items out of order</td><td><strong>Again</strong></td></tr></tbody></table><p>The scheduler then updates the card from that grade. See <a href="./Grading">Grading</a>.</p><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Keep lists short (about 3 to 7 items) so reviews stay manageable.</li><li>Use clear item text so similar options are not easy to confuse.</li><li>Add context in <code>I</code> if the order needs explanation.</li></ul>`,23)])])}const g=a(i,[["render",o]]);export{u as __pageData,g as default};
